const allowed = new Set(['lead_id','source','language','service','contact_consent','created_at']);
const prohibited = ['name','phone','email','child_name','diagnosis','medical_notes','message'];

return items.map((item) => {
  const keys = Object.keys(item.json);
  const unexpected = keys.filter((key) => !allowed.has(key));
  const presentProhibited = prohibited.filter((key) => item.json[key] !== undefined);

  if (unexpected.length || presentProhibited.length) {
    throw new Error(`Preview payload rejected. Unexpected: ${unexpected.join(',')}; prohibited: ${presentProhibited.join(',')}`);
  }

  if (item.json.contact_consent !== true) {
    throw new Error('Preview payload rejected: contact consent must be true.');
  }

  const idempotencyKey = `${item.json.source}:${item.json.lead_id}`;

  return {
    json: {
      ...item.json,
      idempotency_key: idempotencyKey,
      preview_only: true,
      contains_real_pii: false
    }
  };
});

return items.map((item) => ({
  json: {
    event_type: 'internal_new_lead_preview',
    severity: 'info',
    route_to: 'staff-preview-queue',
    lead_reference: item.json.lead_id,
    source: item.json.source,
    language: item.json.language,
    service: item.json.service,
    idempotency_key: item.json.idempotency_key,
    preview_only: true,
    outbound_message_sent: false,
    external_write_performed: false
  }
}));
